def sendEmailMsg(formData):
    HTML = DR_MSG_HTML.replace("{{NAME}}", formData.first_name)
    HTML = HTML.replace("{{REGNO}}", "DELE- "+str(formData.id))
    HTML = HTML.replace("{{DATE}}", str(formData.created_at.date()))
    
    send_mail('Registration Confirmed | Welcome to CPLD 2025, Lucknow!', '', settings.EMAIL_HOST_USER, [formData.email],html_message=HTML)